+/// Fold (icmp ult (add A, B), A) | (icmp ult (add A, B), B) -> (icmp ult (add A, B), A)
+/// Also handles commuted variants like (icmp ugt A, (add A, B)) | (icmp ult (add A, B), B).
+/// Both conditions detect unsigned overflow of A+B and are equivalent.
+/// Commuted variants are handled by swapping LHS/RHS.
+static Value *foldOrOfEquivalentOverflowChecks(ICmpInst *ICmp1, ICmpInst *ICmp2,
+                                               bool IsAnd,
+                                               InstCombiner::BuilderTy &Builder) {
+  if (IsAnd)
+    return nullptr;  // Only handle OR for now
+
+  ICmpInst::Predicate Pred1 = ICmp1->getPredicate();
+  ICmpInst::Predicate Pred2 = ICmp2->getPredicate();
+
+  Value *LHS0 = ICmp1->getOperand(0);
+  Value *LHS1 = ICmp1->getOperand(1);
+  Value *RHS0 = ICmp2->getOperand(0);
+  Value *RHS1 = ICmp2->getOperand(1);
+
+  // Normalize: convert (icmp ugt A, S) to (icmp ult S, A) for comparison purposes
+  // We need to check if both icmps are checking for overflow of the same add
+  Value *Add1 = nullptr, *Other1 = nullptr;
+  Value *Add2 = nullptr, *Other2 = nullptr;
+
+  // Check ICmp1: either (icmp ult Add, Other) or (icmp ugt Other, Add)
+  if (Pred1 == ICmpInst::ICMP_ULT && match(LHS0, m_Add(m_Value(), m_Value()))) {
+    Add1 = LHS0;
+    Other1 = LHS1;
+  } else if (Pred1 == ICmpInst::ICMP_UGT && match(RHS0, m_Add(m_Value(), m_Value()))) {
+    Add1 = RHS0;
+    Other1 = LHS0;
+  } else {
+    return nullptr;
+  }
+
+  // Check ICmp2: either (icmp ult Add, Other) or (icmp ugt Other, Add)
+  if (Pred2 == ICmpInst::ICMP_ULT && match(RHS0, m_Add(m_Value(), m_Value()))) {
+    Add2 = RHS0;
+    Other2 = RHS1;
+  } else if (Pred2 == ICmpInst::ICMP_UGT && match(LHS1, m_Add(m_Value(), m_Value()))) {
+    Add2 = LHS1;
+    Other2 = RHS0;
+  } else {
+    return nullptr;
+  }
+
+  // Both must be the same add instruction
+  if (Add1 != Add2)
+    return nullptr;
+
+  Value *A, *B;
+  // Match Add1 as (add A, B)
+  if (!match(Add1, m_c_Add(m_Value(A), m_Value(B))))
+    return nullptr;
+
+  // Check if Other1 and Other2 are the two addends (in any order)
+  bool Other1isA = (Other1 == A);
+  bool Other1isB = (Other1 == B);
+  bool Other2isA = (Other2 == A);
+  bool Other2isB = (Other2 == B);
+
+  // We need Other1 and Other2 to be different addends
+  if (!((Other1isA && Other2isB) || (Other1isB && Other2isA)))
+    return nullptr;
+
+  // Both conditions are equivalent (both detect unsigned overflow),
+  // so the OR simplifies to just one of them.
+  return ICmp1;
+}
+
+
 struct IntPart {
   Value *From;
   unsigned StartBit;
@@ -3153,6 +3222,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return X;
     if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
